// TestClassifier_PathIntentRoutesToPathRAG verifies that queries with path keywords
// and extractable entity IDs properly set PathIntent=true, extract the start node,
// and route to StrategyPathRAG via InferStrategy().
func TestClassifier_PathIntentRoutesToPathRAG(t *testing.T) {
	classifier := &KeywordClassifier{}
	ctx := context.Background()

	tests := []struct {
		name              string
		query             string
		wantPathIntent    bool
		wantPathStartNode string
		wantStrategy      SearchStrategy
	}{
		{
			name:              "related_to_with_entity_id",
			query:             "What is related to sensor-001?",
			wantPathIntent:    true,
			wantPathStartNode: "sensor-001",
			wantStrategy:      StrategyPathRAG,
		},
		{
			name:              "connected_to_with_entity_id",
			query:             "Show everything connected to pump-42",
			wantPathIntent:    true,
			wantPathStartNode: "pump-42",
			wantStrategy:      StrategyPathRAG,
		},
		{
			name:              "path_between_with_first_entity",
			query:             "Find path between device-abc and zone-A",
			wantPathIntent:    true,
			wantPathStartNode: "device-abc", // Should extract first entity
			wantStrategy:      StrategyPathRAG,
		},
		{
			name:              "links_to_with_entity_id",
			query:             "what links to controller-99?",
			wantPathIntent:    true,
			wantPathStartNode: "controller-99",
			wantStrategy:      StrategyPathRAG,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			opts := classifier.ClassifyQuery(ctx, tt.query)

			if opts == nil {
				t.Fatal("expected non-nil SearchOptions")
			}

			if opts.Query != tt.query {
				t.Errorf("original query not preserved: got %q, want %q", opts.Query, tt.query)
			}

			if opts.PathIntent != tt.wantPathIntent {
				t.Errorf("PathIntent mismatch: got %v, want %v", opts.PathIntent, tt.wantPathIntent)
			}

			if opts.PathStartNode != tt.wantPathStartNode {
				t.Errorf("PathStartNode mismatch: got %q, want %q", opts.PathStartNode, tt.wantPathStartNode)
			}

			strategy := opts.InferStrategy()
			if strategy != tt.wantStrategy {
				t.Errorf("strategy mismatch: got %q, want %q", strategy, tt.wantStrategy)
			}
		})
	}
}

