// TestClassifier_SpatialPopulatesGeoBounds verifies that true spatial queries
// (with coordinates and radius) populate GeoBounds with a bounding box and
// route to StrategyGeoGraphRAG via InferStrategy().
func TestClassifier_SpatialPopulatesGeoBounds(t *testing.T) {
	classifier := &KeywordClassifier{}
	ctx := context.Background()

	tests := []struct {
		name         string
		query        string
		wantStrategy SearchStrategy
		checkBounds  bool
	}{
		{
			name:         "within_km_with_coords",
			query:        "Find entities within 5km of 40.7128,-74.0060",
			wantStrategy: StrategyGeoGraphRAG,
			checkBounds:  true,
		},
		{
			name:         "within_miles_with_coords",
			query:        "Show devices within 10 miles of 34.0522,-118.2437",
			wantStrategy: StrategyGeoGraphRAG,
			checkBounds:  true,
		},
		{
			name:         "within_meters_with_coords",
			query:        "Sensors within 500m of 51.5074,-0.1278",
			wantStrategy: StrategyGeoGraphRAG,
			checkBounds:  true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			opts := classifier.ClassifyQuery(ctx, tt.query)

			if opts == nil {
				t.Fatal("expected non-nil SearchOptions")
			}

			if tt.checkBounds {
				if opts.GeoBounds == nil {
					t.Fatal("expected GeoBounds to be populated for spatial query")
				}

				// Verify bounding box is valid
				if opts.GeoBounds.North <= opts.GeoBounds.South {
					t.Errorf("invalid bounds: North (%f) should be > South (%f)",
						opts.GeoBounds.North, opts.GeoBounds.South)
				}

				if opts.GeoBounds.East <= opts.GeoBounds.West {
					t.Errorf("invalid bounds: East (%f) should be > West (%f)",
						opts.GeoBounds.East, opts.GeoBounds.West)
				}

				// Verify bounds are non-zero (actual coordinates extracted)
				if opts.GeoBounds.North == 0 && opts.GeoBounds.South == 0 &&
					opts.GeoBounds.East == 0 && opts.GeoBounds.West == 0 {
					t.Error("GeoBounds should not be all zeros for valid spatial query")
				}
			}

			strategy := opts.InferStrategy()
			if strategy != tt.wantStrategy {
				t.Errorf("strategy mismatch: got %q, want %q", strategy, tt.wantStrategy)
			}
		})
	}
}

